+#include <bench/bench.h>
+#include <netbase.h>
+#include <netgroup.h>
+#include <node/data/ip_asn.dat.h>
+#include <util/asmap.h>
+
+// GetMappedAS benchmarks cover individual IP lookups and a multi-IP lookup.
+// For lookups, the embedded ASMap file is used, which might change over
+// time. To avoid looking up unmapped IPs in benchmarks, the individual IPs
+// are chosen to be well-known IPs that likely won't be unmapped anytime
+// soon. The IPs for the multi-lookup benchmark are randomly sampled from
+// different ASNs to ensure a mix of lookup times. Some of these could be
+// unmapped when upgrading the embedded ASMap file, which will cause the
+// benchmarks to assert and the IPs will need to be updated or changed.
+
+static void BenchGetMappedAS(benchmark::Bench& bench, const std::vector<CNetAddr>& addrs, bool check)
+{
+    std::span<const std::byte> asmap{node::data::ip_asn};
+    assert(!asmap.empty() && CheckStandardAsmap(asmap));
+    auto netgroupman{NetGroupManager::WithEmbeddedAsmap(asmap)};
+
+    if (check) {
+        for (const CNetAddr& addr : addrs) {
+            assert(netgroupman.GetMappedAS(addr) > 0);
+        }
+    }
+
+    bench.run([&] {
+        for (const CNetAddr& addr : addrs) {
+            ankerl::nanobench::doNotOptimizeAway(netgroupman.GetMappedAS(addr));
+        }
+    });
+}
+
+static void AsMapGetMappedASQuad9v4(benchmark::Bench& bench)
+{
+    std::vector<CNetAddr> addrs{LookupHost("9.9.9.9", false).value()};

